const item = $input.first().json;
const message = item.body.message || {};
const callbackQuery = item.body.callback_query || {};

const chatId = (message.chat?.id || callbackQuery.message?.chat?.id)?.toString();
const firstName = message.from?.first_name || callbackQuery.from?.first_name || "Utente";
const lastName = message.from?.last_name || callbackQuery.from?.last_name || "";
const language = message.from?.language_code || callbackQuery.from?.language_code || "it";

// --- ESTREZIONE DINAMICA DEL BASE URL DELLA MINIAPP ---
const baseUrl = item.urlMiniApp || "https://trinaibusinessoperatingsystem.github.io/";

// --- ESTRAZIONE DINAMICA DEL MESSAGE ID ---
const msgId = (message.message_id || callbackQuery.message?.message_id || 1).toString();

// 1. Struttura dei dati di Onboarding di Default per lo stakeholder standalone
const stakeholderData = {
  sessionId: `${chatId}`,
  name: firstName,
  surname: lastName,
  standalone_context: {
    language: language,
    company_context_string: "",
    kyc_details: {
      professional_questionnaire: {
        role: "",
        team_size: "",
        hard_skills: []
      }
    }
  },
  professional_profile: {
    soft_skills_modules: {
       modulo1: { completed: false, date: null, time: null, results: null },
       modulo2: { completed: false, date: null, time: null, results: null },
       modulo3: { completed: false, date: null, time: null, results: null },
       modulo4: { completed: false, date: null, time: null, results: null }
    }
  },
  behavioral_profile: {
    big_five: {
      openness_to_experience: 50,
      conscientiousness: 50,
      extraversion: 50,
      agreeableness: 50,
      neuroticism: 50
    },
    notes: "Profilo standalone inizializzato via Telegram."
  }
};

// 2. LOGICA GENERAZIONE ASH (Identica allo standard di produzione)
function generateSignature(str, key) {
    let hash = 0; const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        const char = combined.charCodeAt(i);
        hash = ((hash << 5) - hash) + char; hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}

const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const ts = Date.now().toString();

// Utilizziamo l'UUID corretto per questo specifico webhook standalone
const WEBHOOK_UUID = "e34e22de-0725-4410-a882-75e87e359376"; 
const payloadASH = `${chatId}|${ts}|${WEBHOOK_UUID}`;

const ash = `${Buffer.from(payloadASH).toString('base64')}.${generateSignature(payloadASH, SECRET_KEY)}`;

// 3. COSTRUZIONE DEL PAYLOAD CON BASE URL DINAMICO
const textMessage = `📊 <b>Analisi delle Competenze Trasversali</b>\n━━━━━━━━━━━━━━━━━━━━\nCiao <b>${firstName}</b>,\n\nQuesto strumento ti permette di mappare le tue principali competenze interpersonali e organizzative: gestione dello stress, stile decisionale, comunicazione e attitudine strategica.\n\nAttraverso l'analisi di situazioni lavorative reali, genereremo un profilo dettagliato utile a ottimizzare la tua attività quotidiana e supportare la tua crescita professionale.\n\n<i>Seleziona il pulsante in basso per inserire i dati iniziali e avviare il percorso.</i>`;

const buttons = [
    [{ 
        text: "📋 Inizia Configurazione", 
        web_app: { url: `${baseUrl}onboarding.html?ash=${ash}&msg_id=${msgId}&alone=true` } 
    }]
];

return [{
  json: {
    ...item,
    chat_id: chatId,
    first_name: firstName,
    ash: ash,
    msg_id: msgId,
    stakeholder_document: stakeholderData,
    telegramApiPayload: {
        method: "sendMessage",
        chat_id: chatId,
        text: textMessage,
        parse_mode: "HTML",
        reply_markup: { inline_keyboard: buttons }
    }
  }
}];

