const payloadASH = `${chatId}|${ts}|${WEBHOOK_UUID}`;
const newAsh = `${Buffer.from(payloadASH).toString('base64')}.${generateSignature(payloadASH, SECRET_KEY)}`;

// --- COSTRUZIONE PAYLOAD EDIT TELEGRAM ---
