});

return results;

/**
 * SOFT SKILLS MODULE UPDATER - N8N COMPATIBLE
 * Aggiorna lo stakeholder_profile con i risultati della valutazione del modulo
 */

const items = $input.all();

const results = items.map(item => {
    const data = item.json;
    const moduleId = data.body.module_id; 
