            modulo2: { completed: false, date: null, time: null, results: null, timestamp: null },
            modulo3: { completed: false, date: null, time: null, results: null, timestamp: null },
            modulo4: { completed: false, date: null, time: null, results: null, timestamp: null }
        };
    }

    // Timestamp attuale
    const now = new Date().toISOString();

    // 🔥 AGGIORNA IL MODULO SPECIFICO CON I DATI DEL LLM
    stakeholder.professional_profile.soft_skills_modules[moduleId] = {
        completed: true,
        completion_date: now,
        evaluation: {
