const item = $input.first().json;
const stakeholder = item.stakeholder;
const body = item.body || {};

// Estrazione parametri
const chatId = Number(stakeholder.owner_data_ref?.chat_id || body._auth?.user?.id || 720379727);
const msgId = Number(body.msg_id || 1);
const baseUrl = item.urlMiniApp || "https://trinaibusinessoperatingsystem.github.io/";

// Estrai il profilo completo generato dall'AI
