const payloadASH = `${chatId}|${ts}|${WEBHOOK_UUID}`;
const freshAsh = `${Buffer.from(payloadASH).toString('base64')}.${generateSignature(payloadASH, SECRET_KEY)}`;

if (isScenarioCurrentlyActive) {
    buttons = [
