// 1. Recuperiamo l'output strutturato del sub-workflow
const inputData = $input.first().json;
const evaluation = inputData.Evaluation || inputData;

// 2. Recuperiamo in modo sicuro lo stakeholder originale dal nodo 'Merger' conversazionale
let stakeholder;
let rawChatId;

try {
    const mergerNode = $('Merger').first().json;
    stakeholder = mergerNode.stakeholder_document;
    rawChatId = mergerNode.chat_id;
} catch (error) {
    throw new Error("Errore nel recupero dello stakeholder_document dal nodo 'Merger': " + error.message);
}

// Casting del chat_id in numero intero per garantire la compatibilità con MongoDB e Telegram
const chatId = parseInt(rawChatId, 10);
if (isNaN(chatId)) {
    throw new Error("Errore: chat_id non valido o non convertibile in intero.");
}

// 3. Inizializzazione sicura delle strutture nidificate del profilo
if (!stakeholder.professional_profile) {
    stakeholder.professional_profile = {};
}
if (!stakeholder.professional_profile.soft_skills_complete_profile) {
    stakeholder.professional_profile.soft_skills_complete_profile = {};
}

const completeProfile = stakeholder.professional_profile.soft_skills_complete_profile;
const updates = evaluation.complete_profile_updates;

// 4. Merge selettivo e puntuale solo delle chiavi dinamiche modificate dall'LLM
if (updates) {
    if (updates.areas_to_improve) {
        completeProfile.areas_to_improve = updates.areas_to_improve;
    }
    if (updates.strengths) {
        completeProfile.strengths = updates.strengths;
    }
    if (updates.recommended_videos) {
        completeProfile.recommended_videos = updates.recommended_videos;
    }
    if (updates.stats) {
        if (!completeProfile.stats) {
            completeProfile.stats = {};
        }
        if (updates.stats.overall_score !== undefined) {
            // Arrotonda il punteggio a 2 cifre decimali per consistenza grafica
            completeProfile.stats.overall_score = parseFloat(updates.stats.overall_score);
        }
    }
}

// 5. Aggiornamento dei metadati di ultima modifica
if (!stakeholder.metadata) {
    stakeholder.metadata = {};
}
stakeholder.metadata.last_updated = new Date().toISOString();

// 6. Output finale per la scrittura su MongoDB (senza alcuna perdita di dati storici)
return [{
    json: {
        chat_id: chatId,
        stakeholder_document: stakeholder,
        success: true
    }
}];
